import React from 'react';
import {
  Box,
  Typography,
  Grid,
  useTheme,
  styled
} from '@mui/material';
import {
  Speed,
  Timer,
  DirectionsCar,
  LocalGasStation,
  CalendarToday
} from '@mui/icons-material';

const IconBox = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  padding: theme.spacing(1.5),
  '& svg': {
    fontSize: '2rem',
    marginBottom: theme.spacing(1),
    color: theme.palette.primary.main,
  }
}));

interface CarSpecificationsIconsProps {
  engine?: string;
  power?: string;
  acceleration?: string;
  maxSpeed?: string;
  fuel?: string;
  year?: string | number;
}

const CarSpecificationsIcons: React.FC<CarSpecificationsIconsProps> = ({
  engine,
  power,
  acceleration,
  maxSpeed,
  fuel,
  year
}) => {
  const theme = useTheme();

  return (
    <Grid container spacing={2} sx={{ mt: 1, mb: 3 }}>
      {power && (
        <Grid item xs={4} sm={2}>
          <IconBox>
            <Speed />
            <Typography variant="body2" textAlign="center" fontWeight={500}>
              {power}
            </Typography>
            <Typography variant="caption" textAlign="center" color="text.secondary">
              Мощность
            </Typography>
          </IconBox>
        </Grid>
      )}
      
      {engine && (
        <Grid item xs={4} sm={2}>
          <IconBox>
            <DirectionsCar />
            <Typography variant="body2" textAlign="center" fontWeight={500}>
              {engine}
            </Typography>
            <Typography variant="caption" textAlign="center" color="text.secondary">
              Двигатель
            </Typography>
          </IconBox>
        </Grid>
      )}
      
      {acceleration && (
        <Grid item xs={4} sm={2}>
          <IconBox>
            <Timer />
            <Typography variant="body2" textAlign="center" fontWeight={500}>
              {acceleration}
            </Typography>
            <Typography variant="caption" textAlign="center" color="text.secondary">
              Разгон
            </Typography>
          </IconBox>
        </Grid>
      )}
      
      {maxSpeed && (
        <Grid item xs={4} sm={2}>
          <IconBox>
            <Speed />
            <Typography variant="body2" textAlign="center" fontWeight={500}>
              {maxSpeed}
            </Typography>
            <Typography variant="caption" textAlign="center" color="text.secondary">
              Макс. скорость
            </Typography>
          </IconBox>
        </Grid>
      )}
      
      {fuel && (
        <Grid item xs={4} sm={2}>
          <IconBox>
            <LocalGasStation />
            <Typography variant="body2" textAlign="center" fontWeight={500}>
              {fuel}
            </Typography>
            <Typography variant="caption" textAlign="center" color="text.secondary">
              Топливо
            </Typography>
          </IconBox>
        </Grid>
      )}
      
      {year && (
        <Grid item xs={4} sm={2}>
          <IconBox>
            <CalendarToday />
            <Typography variant="body2" textAlign="center" fontWeight={500}>
              {year}
            </Typography>
            <Typography variant="caption" textAlign="center" color="text.secondary">
              Год выпуска
            </Typography>
          </IconBox>
        </Grid>
      )}
    </Grid>
  );
};

export default CarSpecificationsIcons;
